"use client";

import { useEffect, useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { productsApi } from "@/lib/api";
import { getUploadUrl } from "@/lib/utils";
import { toast } from "sonner";
import { AxiosError } from "axios";

import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Loader2, Package, Upload, X } from "lucide-react";

interface Product {
  id: number;
  sku: string;
  name: string;
  category: string;
  image_url: string | null;
  price_buy: number | string;
  price_sell: number | string;
  stock: number | string;
  min_stock_alert: number | string;
}

interface ProductFormDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  product: Product | null;
}

function numericToString(value: number | string | null | undefined, fallback = "") {
  if (value === null || value === undefined) return fallback;
  return String(value);
}

export function ProductFormDialog({
  open,
  onOpenChange,
  product,
}: ProductFormDialogProps) {
  const queryClient = useQueryClient();
  const isEditing = !!product;

  const [sku, setSku] = useState("");
  const [name, setName] = useState("");
  const [category, setCategory] = useState("");
  const [priceBuy, setPriceBuy] = useState("");
  const [priceSell, setPriceSell] = useState("");
  const [stock, setStock] = useState("0");
  const [minStockAlert, setMinStockAlert] = useState("5");
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);

  useEffect(() => {
    if (!open) return;

    if (product) {
      setSku(product.sku);
      setName(product.name);
      setCategory(product.category);
      setPriceBuy(numericToString(product.price_buy));
      setPriceSell(numericToString(product.price_sell));
      setStock(numericToString(product.stock, "0"));
      setMinStockAlert(numericToString(product.min_stock_alert, "5"));
      setImagePreview(getUploadUrl(product.image_url));
    } else {
      setSku("");
      setName("");
      setCategory("");
      setPriceBuy("");
      setPriceSell("");
      setStock("0");
      setMinStockAlert("5");
      setImagePreview(null);
    }

    setImageFile(null);
  }, [open, product]);

  const mutation = useMutation({
    mutationFn: async () => {
      const formData = new FormData();
      formData.append("sku", sku.toUpperCase());
      formData.append("name", name);
      formData.append("category", category);
      formData.append("price_buy", priceBuy);
      formData.append("price_sell", priceSell);
      formData.append("stock", stock || "0");
      formData.append("min_stock_alert", minStockAlert || "5");
      if (imageFile) formData.append("image", imageFile);

      if (isEditing) {
        return productsApi.update(product.id, formData);
      }
      return productsApi.create(formData);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["products"] });
      queryClient.invalidateQueries({ queryKey: ["products", "low-stock"] });
      queryClient.invalidateQueries({ queryKey: ["dashboard"] });
      toast.success(isEditing ? "Produk berhasil diperbarui" : "Produk berhasil ditambahkan");
      onOpenChange(false);
    },
    onError: (error: AxiosError<{ message?: string }>) => {
      toast.error(
        error.response?.data?.message ||
          (isEditing ? "Gagal memperbarui produk" : "Gagal menambah produk")
      );
    },
  });

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const allowedTypes = ["image/jpeg", "image/jpg", "image/png", "image/gif"];
    if (!allowedTypes.includes(file.type)) {
      toast.error("Format file tidak didukung. Gunakan JPEG, PNG, atau GIF.");
      return;
    }

    if (file.size > 2 * 1024 * 1024) {
      toast.error("Ukuran file terlalu besar. Maksimal 2MB.");
      return;
    }

    setImageFile(file);
    setImagePreview(URL.createObjectURL(file));
  };

  const removeImage = () => {
    setImageFile(null);
    setImagePreview(null);
  };

  const handleSubmit = (event: React.FormEvent) => {
    event.preventDefault();

    if (!sku.trim() || !name.trim() || !category.trim() || !priceBuy || !priceSell) {
      toast.error("SKU, nama, kategori, harga beli, dan harga jual wajib diisi");
      return;
    }

    const buy = Number(priceBuy);
    const sell = Number(priceSell);
    const stockNum = Number(stock || "0");
    const minStock = Number(minStockAlert || "0");

    if (Number.isNaN(buy) || Number.isNaN(sell) || buy < 0 || sell < 0) {
      toast.error("Harga beli dan harga jual harus berupa angka valid");
      return;
    }

    if (Number.isNaN(stockNum) || stockNum < 0 || Number.isNaN(minStock) || minStock < 0) {
      toast.error("Stok dan minimal stok harus berupa angka positif atau nol");
      return;
    }

    mutation.mutate();
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[520px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{isEditing ? "Edit Produk" : "Tambah Produk Baru"}</DialogTitle>
          <DialogDescription>
            {isEditing
              ? "Perbarui informasi produk"
              : "Isi data produk baru di bawah ini"}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="flex items-center gap-4">
            <div className="relative">
              {imagePreview ? (
                <div className="relative">
                  <img
                    src={imagePreview}
                    alt="Preview"
                    className="size-16 rounded-lg object-cover border"
                  />
                  <button
                    type="button"
                    onClick={removeImage}
                    className="absolute -top-1 -right-1 flex size-5 items-center justify-center rounded-full bg-destructive text-white text-xs hover:bg-destructive/90"
                  >
                    <X className="size-3" />
                  </button>
                </div>
              ) : (
                <div className="size-16 rounded-lg border bg-muted flex items-center justify-center">
                  <Package className="size-6 text-muted-foreground" />
                </div>
              )}
            </div>

            <div>
              <Label htmlFor="product-image" className="cursor-pointer">
                <span className="inline-flex items-center gap-1.5 text-sm text-primary hover:underline">
                  <Upload className="size-3.5" />
                  {imagePreview ? "Ganti Gambar" : "Unggah Gambar"}
                </span>
              </Label>
              <input
                id="product-image"
                type="file"
                accept="image/jpeg,image/jpg,image/png,image/gif"
                onChange={handleImageChange}
                className="hidden"
              />
              <p className="text-xs text-muted-foreground mt-0.5">
                JPEG, PNG, GIF. Maks 2MB
              </p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="sku">
                SKU <span className="text-destructive">*</span>
              </Label>
              <Input
                id="sku"
                value={sku}
                onChange={(e) => setSku(e.target.value.toUpperCase())}
                placeholder="OLI-001"
                className="uppercase"
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="category">
                Kategori <span className="text-destructive">*</span>
              </Label>
              <Input
                id="category"
                value={category}
                onChange={(e) => setCategory(e.target.value)}
                placeholder="Oli Mesin"
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="name">
              Nama Produk <span className="text-destructive">*</span>
            </Label>
            <Input
              id="name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Contoh: Castrol Magnatec 10W40"
              required
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="price_buy">
                Harga Beli <span className="text-destructive">*</span>
              </Label>
              <Input
                id="price_buy"
                type="number"
                min="0"
                step="0.01"
                value={priceBuy}
                onChange={(e) => setPriceBuy(e.target.value)}
                placeholder="0"
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="price_sell">
                Harga Jual <span className="text-destructive">*</span>
              </Label>
              <Input
                id="price_sell"
                type="number"
                min="0"
                step="0.01"
                value={priceSell}
                onChange={(e) => setPriceSell(e.target.value)}
                placeholder="0"
                required
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="stock">Stok Awal</Label>
              <Input
                id="stock"
                type="number"
                min="0"
                value={stock}
                onChange={(e) => setStock(e.target.value)}
                placeholder="0"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="min_stock_alert">Batas Minimum Stok</Label>
              <Input
                id="min_stock_alert"
                type="number"
                min="0"
                value={minStockAlert}
                onChange={(e) => setMinStockAlert(e.target.value)}
                placeholder="5"
              />
            </div>
          </div>

          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
              Batal
            </Button>
            <Button type="submit" disabled={mutation.isPending}>
              {mutation.isPending ? (
                <>
                  <Loader2 className="size-4 animate-spin" />
                  Menyimpan...
                </>
              ) : isEditing ? (
                "Simpan Perubahan"
              ) : (
                "Tambah Produk"
              )}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}
